*event_7
;[exp] onObjectTrigger

[if exp='game.party.hasItem(o.古代語の辞書)']
	@notice text="Written in ancient language, it reads:<r><y>The queen hid the key to the King's tomb somewhere on this floor."
[else]
	@notice text="<y>There are characters written on it, but they are in an ancient language and cannot be read."
[endif]

